<template>
	<div>
		<el-dialog modal-class="edit_form_modal" class="edit_form" v-model="formVisible" :title="formTitle" width="80%" destroy-on-close :fullscreen='false'>
			<el-form class="formModel_form" ref="formRef" :model="form" :rules="rules">
				<el-row >
					<el-col :span="12">
						<el-form-item label="食谱名称" prop="shipumingcheng">
							<el-input class="list_inp" v-model="form.shipumingcheng" placeholder="食谱名称"
                                type="text"
								:readonly="!isAdd||disabledForm.shipumingcheng?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item prop="shiputupian"
									  label="食谱图片"
						>
							<uploads
								:disabled="!isAdd||disabledForm.shiputupian?true:false"
								action="file/upload"
								tip="请上传食谱图片"
								style="width: 100%;text-align: left;"
								:fileUrls="form.shiputupian?form.shiputupian:''"
								@change="shiputupianUploadSuccess">
							</uploads>
						</el-form-item>
					</el-col>
					<el-col :span="12">
						<el-form-item label="食谱分类" prop="shipufenlei">
							<el-select
								class="list_sel"
								:disabled="!isAdd||disabledForm.shipufenlei?true:false"
								v-model="form.shipufenlei"
								placeholder="请选择食谱分类"
								>
								<el-option v-for="(item,index) in shipufenleiLists" :label="item"
									:value="item"
									>
								</el-option>
							</el-select>
						</el-form-item>
					</el-col>
					<el-col :span="12">
						<el-form-item label="食材" prop="shicai">
							<el-input class="list_inp" v-model="form.shicai" placeholder="食材"
                                type="text"
								:readonly="!isAdd||disabledForm.shicai?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="配料" prop="peiliao">
							<el-input class="list_inp" v-model="form.peiliao" placeholder="配料"
                                type="text"
								:readonly="!isAdd||disabledForm.peiliao?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="适宜人群" prop="shiyirenqun">
							<el-input class="list_inp" v-model="form.shiyirenqun" placeholder="适宜人群"
                                type="text"
								:readonly="!isAdd||disabledForm.shiyirenqun?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="12">
						<el-form-item label="相关技巧" prop="xiangguanjiqiao">
							<el-input class="list_inp" v-model="form.xiangguanjiqiao" placeholder="相关技巧"
                                type="text"
								:readonly="!isAdd||disabledForm.xiangguanjiqiao?true:false" />
						</el-form-item>
					</el-col>

					<el-col :span="24">
						<el-form-item label="烹饪步骤" prop="pengrenbuzhou">
							<el-input v-model="form.pengrenbuzhou" placeholder="烹饪步骤" type="textarea"
							:readonly="!isAdd||disabledForm.pengrenbuzhou?true:false"
							/>
						</el-form-item>
					</el-col>
					<el-col :span="24">
						<el-form-item label="制作方式" prop="zhizuofangshi">
							<el-input v-model="form.zhizuofangshi" placeholder="制作方式" type="textarea"
							:readonly="!isAdd||disabledForm.zhizuofangshi?true:false"
							/>
						</el-form-item>
					</el-col>
					<el-col :span="24">
						<el-form-item label="食谱介绍" prop="shipujieshao">
							<editor :value="form.shipujieshao" placeholder="请输入食谱介绍" :readonly="!isAdd||disabledForm.shipujieshao?true:false"
								class="list_editor" @change="(e)=>editorChange(e,'shipujieshao')"></editor>
						</el-form-item>
					</el-col>
				</el-row>
			</el-form>
			<template #footer v-if="isAdd||type=='logistics'||type=='reply'">
				<span class="formModel_btn_box">
					<el-button class="cancel_btn" @click="closeClick">取消</el-button>
					<el-button class="confirm_btn" type="primary" @click="save"
						>
						提交
					</el-button>
				</span>
			</template>
		</el-dialog>
	</div>
</template>
<script setup>
	import {
		reactive,
		ref,
		getCurrentInstance,
		nextTick,
		computed,
		defineEmits
	} from 'vue'
    import {
        useStore
    } from 'vuex';
    const store = useStore()
    const user = computed(()=>store.getters['user/session'])
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const emit = defineEmits(['formModelChange'])
	//基础信息
	const tableName = 'shipuxinxi'
	const formName = '食谱信息'
	//基础信息
	//form表单
	const form = ref({})
	const disabledForm = ref({
        shipumingcheng : false,
        shiputupian : false,
        shipufenlei : false,
        shicai : false,
        peiliao : false,
        pengrenbuzhou : false,
        zhizuofangshi : false,
        shipujieshao : false,
        shiyirenqun : false,
        xiangguanjiqiao : false,
        clicktime : false,
        storeupNumber : false,
        discussNumber : false,
        clickNumber : false,
	})
	const formVisible = ref(false)
	const isAdd = ref(false)
	const formTitle = ref('')

	const rules = ref({
		shipumingcheng: [
		],
		shiputupian: [
		],
		shipufenlei: [
		],
		shicai: [
		],
		peiliao: [
		],
		pengrenbuzhou: [
		],
		zhizuofangshi: [
		],
		shipujieshao: [
		],
		shiyirenqun: [
		],
		xiangguanjiqiao: [
		],
		clicktime: [
		],
		storeupNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		discussNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		clickNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
	})
	//表单验证

	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	//食谱图片上传回调
	const shiputupianUploadSuccess=(e)=>{
		form.value.shiputupian = e
	}
	//食谱分类列表
	const shipufenleiLists = ref([])

	//获取唯一标识
	const getUUID =()=> {
      return new Date().getTime();
    }
	//重置
	const resetForm = () => {
		form.value = {
			shipumingcheng: '',
			shiputupian: '',
			shipufenlei: '',
			shicai: '',
			peiliao: '',
			pengrenbuzhou: '',
			zhizuofangshi: '',
			shipujieshao: '',
			shiyirenqun: '',
			xiangguanjiqiao: '',
			clicktime: '',
		}
	}
	//获取info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			res.data.data.shipujieshao = res.data.data.shipujieshao?(res.data.data.shipujieshao.replace(reg,'../../../project/file')):'';
			form.value = res.data.data
			formVisible.value = true
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//初始化
	const init=(formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null)=>{
		resetForm()
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
			formTitle.value = '新增' + formName
			formVisible.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			formTitle.value = '查看' + formName
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			formTitle.value = '修改' + formName
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			formTitle.value = formNames
			// getInfo()
			for(let x in row){
				if(x=='shipumingcheng'){
					form.value.shipumingcheng = row[x];
					disabledForm.value.shipumingcheng = true;
					continue;
				}
				if(x=='shiputupian'){
					form.value.shiputupian = row[x];
					disabledForm.value.shiputupian = true;
					continue;
				}
				if(x=='shipufenlei'){
					form.value.shipufenlei = row[x];
					disabledForm.value.shipufenlei = true;
					continue;
				}
				if(x=='shicai'){
					form.value.shicai = row[x];
					disabledForm.value.shicai = true;
					continue;
				}
				if(x=='peiliao'){
					form.value.peiliao = row[x];
					disabledForm.value.peiliao = true;
					continue;
				}
				if(x=='pengrenbuzhou'){
					form.value.pengrenbuzhou = row[x];
					disabledForm.value.pengrenbuzhou = true;
					continue;
				}
				if(x=='zhizuofangshi'){
					form.value.zhizuofangshi = row[x];
					disabledForm.value.zhizuofangshi = true;
					continue;
				}
				if(x=='shipujieshao'){
					form.value.shipujieshao = row[x];
					disabledForm.value.shipujieshao = true;
					continue;
				}
				if(x=='shiyirenqun'){
					form.value.shiyirenqun = row[x];
					disabledForm.value.shiyirenqun = true;
					continue;
				}
				if(x=='xiangguanjiqiao'){
					form.value.xiangguanjiqiao = row[x];
					disabledForm.value.xiangguanjiqiao = true;
					continue;
				}
				if(x=='clicktime'){
					form.value.clicktime = row[x];
					disabledForm.value.clicktime = true;
					continue;
				}
				if(x=='storeupNumber'){
					form.value.storeupNumber = row[x];
					disabledForm.value.storeupNumber = true;
					continue;
				}
				if(x=='discussNumber'){
					form.value.discussNumber = row[x];
					disabledForm.value.discussNumber = true;
					continue;
				}
				if(x=='clickNumber'){
					form.value.clickNumber = row[x];
					disabledForm.value.clickNumber = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
			formVisible.value = true
		}

		context?.$http({
			url: `${context?.$toolUtil.storageGet('sessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
		})
		context?.$http({
			url: `option/shipufenlei/shipufenlei`,
			method: 'get'
		}).then(res=>{
			shipufenleiLists.value = res.data.data
		})
	}
	//初始化
	//声明父级调用
	defineExpose({
		init
	})
	//关闭
	const closeClick = () => {
		formVisible.value = false
	}
	//富文本
	const editorChange = (e,name) =>{
		form.value[name] = e
	}
	//提交
	const save= async ()=>{
		if(form.value.shiputupian!=null) {
			form.value.shiputupian = form.value.shiputupian.replace(new RegExp(context?.$config.url,"g"),"");
		}
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//修改跨表数据
					changeCrossData(objcross)
				}else{
					crossUserId = user.value.id
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000,
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get',
						params: params
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post',
								data: form.value
							}).then(async res=>{
								emit('formModelChange')
								context?.$toolUtil.message(`操作成功`,'success')
                                formVisible.value = false
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post',
						data: form.value
					}).then(async (res)=>{
						emit('formModelChange')
						context?.$toolUtil.message(`操作成功`,'success')
                        formVisible.value = false
					})
				}
			}else{
                context.$message.error('请完善信息')
            }
		})
	}
	//修改跨表数据
	const changeCrossData = async (row)=>{
        if(type.value == 'cross'){
            await context?.$http({
                url: `${crossTable.value}/update`,
                method: 'post',
                data: row
            }).then(res=>{})
        }
	}
</script>
<style lang="scss" scoped>
	// 表单
	.formModel_form{
		// form item
		:deep(.el-form-item) {
			//label
			.el-form-item__label {
			}
			// 内容盒子
			.el-form-item__content {
				// 输入框
				.list_inp {
				}
				// 下拉框
				.list_sel {
					//去掉默认样式
					.select-trigger{
						height: 100%;
						.el-input{
							height: 100%;
						}
					}
				}
				// 富文本
				.list_editor {
				}
				// 长文本
				.el-textarea__inner {
				}
				//图片上传样式
				.el-upload-list  {
					//提示语
					.el-upload__tip {
					}
					//外部盒子
					.el-upload--picture-card {
						//图标
						.el-icon{
						}
					}
					.el-upload-list__item {
					}
				}
			}
		}
	}
	// 按钮盒子
	.formModel_btn_box {
		.cancel_btn {
		}
		.cancel_btn:hover {
		}

		.confirm_btn {
		}
		.confirm_btn:hover {
		}
	}
</style>
